#!/bin/sh
set -eu

script_dir="$(CDPATH= cd -- "$(dirname -- "$0")" && pwd)"
repo_dir="$(cd "$script_dir/.." && pwd)"
hooks_json="$repo_dir/config/hooks.json"
offsets_dir="$repo_dir/symbol-offsets"
out_header="$repo_dir/src/hook_config.h"

if [ ! -f "$hooks_json" ]; then
    echo "ERROR: hooks.json not found at $hooks_json" >&2
    exit 1
fi

echo "Generating hook_config.h..."
echo "  hooks.json : $hooks_json"
echo "  offsets dir: $offsets_dir"

cat > "$out_header" <<'HEADER'
// Auto-generated by gen_hook_config.sh from config/hooks.json
// DO NOT EDIT MANUALLY
//
// 每个 file 条目 = 一个 Collector 实例
// 新增模块不需改 collector.cpp — 只需加 handler + hooks.json

#pragma once

#include <stddef.h>
#include <stdbool.h>

class StatsCollector;
class ILogWriter;

// 事件处理函数指针（数据驱动，collector.cpp 只调指针不 switch）
typedef void (*event_handler_fn)(const void *data, const char *hook,
                                  StatsCollector *stats, ILogWriter *writer);

struct hook_cfg {
    const char *name;
    const char *target_path;
    size_t     offset;
    bool       retprobe;
};

struct file_group {
    const char *name;
    const void *embed_data;
    unsigned int embed_size;
    const char *ringbuf_map;
    int         module_id;
    int         hook_count;
    const struct hook_cfg *hooks;
    const char **hook_names;
    event_handler_fn handler;    // ★ 扩展点：新增模块只改这行
};

HEADER

python3 - "$hooks_json" "$offsets_dir" >> "$out_header" <<'PYTHON'
import json, sys, os

with open(sys.argv[1]) as f: config = json.load(f)
offsets_dir = sys.argv[2]
files = config["files"]

# offset cache
cache = {}
def load(lib):
    if lib in cache: return cache[lib]
    of = os.path.join(offsets_dir, f"{lib}.offsets.demangled.tsv")
    if not os.path.exists(of): print(f"// ERROR: {of} missing", file=sys.stderr); sys.exit(1)
    lu = {}
    with open(of) as f:
        f.readline()
        for line in f:
            c = line.rstrip('\n').split('\t')
            if len(c)>=7: lu[c[6]] = c[0]
    cache[lib] = lu; return lu

# extern handler declarations
print("")
print("// ── 每个模块的事件处理函数（外部定义，各自一个 .cpp）──────────")
for fg in files:
    print(f"extern \"C\" void {fg['name']}_event_handler(const void *data, const char *hook, StatsCollector *stats, ILogWriter *writer);")
print("")

# embed data externs
for fg in files:
    n = fg["name"]
    print(f"extern unsigned char {n}_bpf_o[];")
    print(f"extern unsigned int  {n}_bpf_o_len;")
print("")

# hook cfgs per group
total = 0
gi = []
for fg in files:
    name = fg["name"]; lib = fg["lib"]; tp = fg["target_path"]
    lu = load(lib)
    arr = f"hook_cfgs_{name}"; narr = f"hook_names_{name}"
    print(f"// {name}")
    print(f"static const struct hook_cfg {arr}[] = {{")
    for h in fg["hooks"]:
        off = lu.get(h["demangled"])
        if not off: continue
        rp = 1 if h.get("retprobe") else 0
        print(f'    {{"{h["name"]}","{tp}",(size_t){off},{rp}}},')
    print("};")
    print(f"static const char* {narr}[] = {{")
    for h in fg["hooks"]: print(f'    "{h["name"]}",')
    print("};"); print("")
    gi.append((fg,arr,narr,len(fg["hooks"])))
    total += len(fg["hooks"])

# file_groups table
print("static const struct file_group file_groups[] = {")
for fg,arr,narr,hc in gi:
    n = fg["name"]
    print(f'    {{"{n}",{n}_bpf_o,{n}_bpf_o_len,"{fg["ringbuf_map"]}",{fg["module_id"]},{hc},{arr},{narr},{n}_event_handler}},')
print("};")
print(f"#define NUM_FILE_GROUPS {len(files)}")
print(f"#define TOTAL_HOOKS {total}")
print(f"// Generated: {total} hooks, {len(files)} file groups")
PYTHON

echo ""
echo "Generated: $out_header"
echo "Done."
